import{_ as t,o as s,c as a,a0 as i}from"./chunks/framework.Bao410PF.js";const g=JSON.parse('{"title":"Messenger (server-messenger)","description":"","frontmatter":{},"headers":[],"relativePath":"reference/messenger/index.md","filePath":"reference/messenger/index.md"}'),n={name:"reference/messenger/index.md"};function d(r,e,o,c,l,h){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="messenger-server-messenger" tabindex="-1">Messenger (server-messenger) <a class="header-anchor" href="#messenger-server-messenger" aria-label="Permalink to &quot;Messenger (server-messenger)&quot;">​</a></h1><p>The Messenger service is the Hub&#39;s <strong>durable store-and-forward message broker</strong> for analysis-to-analysis (and, generally, identity-to-identity) messaging. It persists messages in a database and exposes a REST send/pull/ack API, with a payload-free Socket.io <strong>wakeup</strong> that tells a recipient to pull. It is analysis-agnostic — the payload is opaque (end-to-end ciphertext for analysis messaging) and <code>analysisId</code>, when present, rides in message metadata.</p><blockquote><p>A legacy Socket.io <strong>relay</strong> (direct <code>send</code> + presence) still runs alongside the broker during the migration to the dedicated node broker; it is removed at decommission.</p></blockquote><h2 id="running" tabindex="-1">Running <a class="header-anchor" href="#running" aria-label="Permalink to &quot;Running&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Development (from repo root)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace=apps/server-messenger</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CLI</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace=apps/server-messenger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Migrations</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace=apps/server-messenger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migration</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Docker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> privateaim/hub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> messenger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><strong>Database</strong> (MySQL / PostgreSQL; SQLite for tests) — durable mailbox</li><li><strong>Redis</strong> — cross-instance wakeup pub/sub + Socket.io adapter</li><li><strong>Authup</strong> — OAuth2 identity provider (token validation on REST + socket connect)</li></ul><h2 id="rest-api" tabindex="-1">REST API <a class="header-anchor" href="#rest-api" aria-label="Permalink to &quot;REST API&quot;">​</a></h2><p>Authenticated as the calling identity (e.g. a node&#39;s <code>client_credentials</code> token). The whole resource is identity-level — there is no analysis in the path.</p><table tabindex="0"><thead><tr><th>Method</th><th>Route</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/messages</code></td><td>Send <code>{ recipients: MessageParty[], data?, metadata? }</code>. Sender = the authenticated identity; recipients are any kind (<code>user</code> / <code>robot</code> / <code>client</code>). One stored row per recipient. Returns the created message ids.</td></tr><tr><td><code>GET</code></td><td><code>/messages?limit=&lt;n&gt;&amp;wait=&lt;ms&gt;</code></td><td>Pull the caller&#39;s pending messages, oldest first. <code>wait</code> enables long-poll: park up to <code>wait</code> ms (capped at 30s) for a pending message before returning empty.</td></tr><tr><td><code>POST</code></td><td><code>/messages/ack</code> <code>{ ids }</code></td><td>Acknowledge messages by id — the broker deletes them (delete-on-ack).</td></tr><tr><td><code>GET</code></td><td><code>/messages/stream</code></td><td>Server-Sent Events stream of payload-free <code>messagePending</code> wakeups for the caller (and one on connect). The client pulls via <code>GET /messages</code> on each event.</td></tr></tbody></table><p>Messages carry a uniform TTL (24h); a background sweep reaps expired rows. Contract types live in <code>@privateaim/messenger-kit</code>; the Hapic client is <code>@privateaim/messenger-http-kit</code>.</p><h2 id="wakeup-messagepending" tabindex="-1">Wakeup (<code>messagePending</code>) <a class="header-anchor" href="#wakeup-messagepending" aria-label="Permalink to &quot;Wakeup (\`messagePending\`)&quot;">​</a></h2><p>When a message is sent, the broker publishes a payload-free wakeup. Across instances it fans out via Redis pub/sub; each instance then notifies its locally-connected recipients through whichever channel they use:</p><ul><li><strong>SSE</strong> (<code>GET /messages/stream</code>) — the preferred push channel: HTTP-native, one-way, no socket.io dependency on the consumer.</li><li><strong>Socket.io</strong> <code>messagePending</code> — the legacy push channel; retired together with the legacy relay at decommission.</li><li><strong>Long-poll</strong> (<code>GET /messages?wait</code>) — the universal fallback when no stream is held; the parked request resolves on the wakeup.</li></ul><p>The payload is never sent over any wakeup channel — it carries only the recipient identity, and the recipient pulls the actual message(s) via REST. A recipient reconnecting a stream should pull once to catch up (the durable mailbox means nothing is lost across gaps).</p><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><h3 id="service-specific" tabindex="-1">Service-Specific <a class="header-anchor" href="#service-specific" aria-label="Permalink to &quot;Service-Specific&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>DB_TYPE</code></td><td><code>better-sqlite3</code></td><td><code>mysql</code>, <code>postgres</code>, or <code>better-sqlite3</code></td></tr><tr><td><code>DB_HOST</code> / <code>DB_PORT</code></td><td>—</td><td>Database connection</td></tr><tr><td><code>DB_USERNAME</code> / <code>DB_PASSWORD</code></td><td>—</td><td>Database credentials</td></tr><tr><td><code>DB_DATABASE</code></td><td>—</td><td>Database name</td></tr><tr><td><code>REDIS_CONNECTION_STRING</code></td><td><code>redis://127.0.0.1</code></td><td>Redis connection (<strong>required</strong>)</td></tr><tr><td><code>AUTHUP_URL</code></td><td><code>http://127.0.0.1:3010/</code></td><td>Authup URL</td></tr></tbody></table><h3 id="inherited" tabindex="-1">Inherited <a class="header-anchor" href="#inherited" aria-label="Permalink to &quot;Inherited&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>NODE_ENV</code></td><td><code>development</code></td><td>Environment</td></tr><tr><td><code>PORT</code></td><td><code>3000</code></td><td>HTTP/WebSocket server port</td></tr><tr><td><code>REALM</code></td><td><code>master</code></td><td>Authup realm</td></tr><tr><td><code>CLIENT_ID</code></td><td><code>system</code></td><td>Authup client ID</td></tr><tr><td><code>CLIENT_SECRET</code></td><td><code>start123</code></td><td>Authup client secret</td></tr></tbody></table><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>Hexagonal, like the other Hub services:</p><ul><li><strong><code>adapters/database/</code></strong> — single <code>message</code> TypeORM entity (uuid pk, <code>created_at</code> ordering, bigint-epoch <code>expires_at</code>), PostgreSQL + MySQL migrations</li><li><strong><code>adapters/http/</code></strong> — thin REST controllers (<code>/messages</code> send/pull/ack) + the SSE wakeup stream (<code>/messages/stream</code>, via <code>routup.createEventStream</code>)</li><li><strong><code>adapters/socket/</code></strong> — connection room-join (keyed by identity) + the legacy <code>messagePending</code> socket emit; the legacy relay/presence handlers (and this socket wakeup) retire at decommission</li><li><strong><code>core/</code></strong> — <code>MessageService</code> (send/pull/ack + long-poll), <code>IMessageRepository</code> port, <code>IMessageWakeup</code> port (in-memory + redis implementations)</li><li><strong><code>app/modules/</code></strong> — <code>ConfigModule</code>, <code>DatabaseModule</code>, <code>WakeupModule</code>, <code>SweeperModule</code> (TTL reaper), <code>HTTPModule</code> (REST + slimmed Socket.io server)</li></ul>`,23)])])}const k=t(n,[["render",d]]);export{g as __pageData,k as default};
